--
-- Clean Schema for Supabase Migration

CREATE TABLE app_user (
    id text PRIMARY KEY,
    name text NOT NULL UNIQUE,
    role text DEFAULT 'user' NOT NULL,
    approved boolean DEFAULT false NOT NULL,
    password_hash text,
    username text UNIQUE,
    password_reset_token_expires_at timestamptz,
    password_reset_token_hash text,
    security_answers text,
    email text UNIQUE,
    phone text
);

CREATE TABLE activity (
    id text PRIMARY KEY,
    user_id text NOT NULL REFERENCES app_user(id) ON DELETE CASCADE,
    action text NOT NULL,
    timestamp timestamptz DEFAULT CURRENT_TIMESTAMP NOT NULL
);
CREATE INDEX idx_activity_user_id ON activity(user_id);
CREATE INDEX idx_activity_timestamp ON activity(timestamp DESC);

CREATE TABLE availability (
    id text PRIMARY KEY,
    week date NOT NULL,
    day text NOT NULL,
    meal text NOT NULL,
    available boolean DEFAULT true NOT NULL,
    note text,
    user_id text NOT NULL REFERENCES app_user(id) ON DELETE CASCADE,
    created_at timestamptz DEFAULT CURRENT_TIMESTAMP NOT NULL
);
CREATE INDEX idx_availability_user_id ON availability(user_id);
CREATE INDEX idx_availability_week ON availability(week);

CREATE TABLE expense (
    id text PRIMARY KEY,
    date date NOT NULL,
    type text NOT NULL,
    category text NOT NULL,
    amount numeric(12, 2) NOT NULL,
    description text NOT NULL,
    user_id text NOT NULL REFERENCES app_user(id) ON DELETE CASCADE,
    created_at timestamptz DEFAULT CURRENT_TIMESTAMP NOT NULL
);
CREATE INDEX idx_expense_user_id ON expense(user_id);
CREATE INDEX idx_expense_date ON expense(date DESC);

CREATE TABLE inventory_item (
    id text PRIMARY KEY,
    name text NOT NULL,
    category text NOT NULL,
    quantity numeric(12, 2) NOT NULL,
    unit text NOT NULL,
    low_stock_threshold numeric(12, 2) DEFAULT 0 NOT NULL,
    last_purchased_at date,
    last_price numeric(12, 2),
    note text,
    user_id text NOT NULL REFERENCES app_user(id),
    created_at timestamptz DEFAULT CURRENT_TIMESTAMP NOT NULL
);

CREATE TABLE menu (
    id text PRIMARY KEY,
    week date NOT NULL,
    purchasers text[],
    user_id text NOT NULL REFERENCES app_user(id),
    created_at timestamptz DEFAULT CURRENT_TIMESTAMP NOT NULL
);
CREATE INDEX idx_menu_week ON menu(week);

CREATE TABLE menu_item (
    id text PRIMARY KEY,
    day text NOT NULL,
    lunch text NOT NULL,
    dinner text NOT NULL,
    lunch_cooks text[],
    dinner_cooks text[],
    menu_id text NOT NULL REFERENCES menu(id) ON DELETE CASCADE
);
CREATE INDEX idx_menu_item_menu_id ON menu_item(menu_id);

CREATE TABLE menu_suggestion (
    id text PRIMARY KEY,
    suggestion text NOT NULL,
    preferred_day text,
    preferred_meal text,
    status text DEFAULT 'pending' NOT NULL,
    user_id text NOT NULL REFERENCES app_user(id),
    created_at timestamptz DEFAULT CURRENT_TIMESTAMP NOT NULL
);

CREATE TABLE monthly_payment (
    id text PRIMARY KEY,
    month date NOT NULL,
    paid boolean NOT NULL,
    amount numeric(12, 2) NOT NULL,
    user_id text NOT NULL REFERENCES app_user(id),
    created_at timestamptz DEFAULT CURRENT_TIMESTAMP NOT NULL,
    expense_id text UNIQUE,
    member_name text,
    reminder_sent boolean DEFAULT false NOT NULL,
    note text,
    payment_type text DEFAULT 'custom'
);
CREATE INDEX idx_monthly_payment_user_id ON monthly_payment(user_id);
CREATE INDEX idx_monthly_payment_month ON monthly_payment(month);

CREATE TABLE notification (
    id text PRIMARY KEY,
    title text NOT NULL,
    message text NOT NULL,
    category text DEFAULT 'general' NOT NULL,
    created_by_id text NOT NULL REFERENCES app_user(id),
    created_at timestamptz DEFAULT CURRENT_TIMESTAMP NOT NULL,
    read_by_user_ids text[] DEFAULT ARRAY[]::text[],
    recipient_user_ids text[] DEFAULT ARRAY[]::text[]
);

CREATE TABLE supply_report (
    id text PRIMARY KEY,
    title text NOT NULL,
    category text NOT NULL,
    item_name text,
    message text NOT NULL,
    status text DEFAULT 'missing' NOT NULL,
    response text,
    created_by_id text NOT NULL REFERENCES app_user(id),
    created_at timestamptz DEFAULT CURRENT_TIMESTAMP NOT NULL,
    updated_at timestamptz NOT NULL
);

